package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.SP;
import java.io.Flushable;
import java.sql.ResultSet;
import java.sql.SQLException;
import static org.mockito.Mockito.*;

import java.io.Appendable;
import java.io.Closeable;
import java.io.IOException;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;

import static org.junit.jupiter.api.Assertions.*;

class CSVPrinterTest {

    @Test
    void close_whenOutIsCloseable_shouldCloseOut() throws IOException {
        Closeable closeableOut = mock(Closeable.class);
        CSVFormat format = mock(CSVFormat.class);
        CSVPrinter printer = new CSVPrinter(closeableOut, format);

        printer.close();

        verify(closeableOut, times(1)).close();
    }

    @Test
    void close_whenOutIsNotCloseable_shouldNotThrow() {
        Appendable nonCloseableOut = new Appendable() {
            @Override
            public Appendable append(CharSequence csq) {
                return this;
            }
            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                return this;
            }
            @Override
            public Appendable append(char c) {
                return this;
            }
        };
        CSVFormat format = mock(CSVFormat.class);
        CSVPrinter printer = new CSVPrinter(nonCloseableOut, format);

        assertDoesNotThrow(new Executable() {
            @Override
            public void execute() throws Throwable {
                printer.close();
            }
        });
    }

    @Test
    void close_whenCloseThrowsIOException_shouldThrow() throws IOException {
        Closeable closeableOut = mock(Closeable.class);
        doThrow(new IOException("close failed")).when(closeableOut).close();
        CSVFormat format = mock(CSVFormat.class);
        CSVPrinter printer = new CSVPrinter(closeableOut, format);

        IOException thrown = assertThrows(IOException.class, printer::close);
        assertEquals("close failed", thrown.getMessage());
    }
}
